// Extract and parse dashboard panels
const dashboardData = $input.first().json;
const dashboard = dashboardData.dashboard;

if (!dashboard || !dashboard.panels) {
  throw new Error('Invalid dashboard data received');
}

const panels = [];

// Process each panel
for (const panel of dashboard.panels) {
  // Skip row panels or panels without content
  if (panel.type === 'row' || !panel.targets) {
    continue;
  }

  const panelInfo = {
    id: panel.id,
    title: panel.title || 'Untitled Panel',
    type: panel.type,
    description: panel.description || '',
    gridPos: panel.gridPos,
    targets: [],
    sql_queries: []
  };

  // Extract SQL queries from targets
  for (const target of panel.targets) {
    if (target.hide) continue; // Skip hidden targets

    panelInfo.targets.push({
      refId: target.refId,
      datasource: target.datasource,
      rawSql: target.rawSql || target.query || '',
      format: target.format,
      expr: target.expr // For Prometheus queries
    });

    // Extract SQL if available
    if (target.rawSql) {
      panelInfo.sql_queries.push({
        refId: target.refId,
        sql: target.rawSql,
        datasource: target.datasource?.name || target.datasource
      });
    } else if (target.query) {
      panelInfo.sql_queries.push({
        refId: target.refId,
        sql: target.query,
        datasource: target.datasource?.name || target.datasource
      });
    }
  }

  panels.push(panelInfo);
}

// Return dashboard metadata and panels
return {
  dashboard: {
    uid: dashboard.uid,
    title: dashboard.title,
    description: dashboard.description || '',
    tags: dashboard.tags || [],
    timezone: dashboard.timezone,
    refresh: dashboard.refresh,
    time: dashboard.time,
    timepicker: dashboard.timepicker,
    templating: dashboard.templating,
    annotations: dashboard.annotations
  },
  panels: panels,
  panelCount: panels.length
};

