// Collect all panel analyses and generate final markdown documentation
const items = $input.all();

if (items.length === 0) {
  return { markdown: '# No panels found for analysis' };
}

// Get dashboard info from first item
const dashboardInfo = items[0].json.dashboard;
const analysisDate = new Date().toISOString().split('T')[0];

// Start building markdown document
let markdown = `# Dashboard Analysis: ${dashboardInfo.title}\n\n`;
markdown += `**Analysis Date:** ${analysisDate}\n`;
markdown += `**Dashboard UID:** ${dashboardInfo.uid}\n`;
markdown += `**Tags:** ${dashboardInfo.tags.join(', ') || 'None'}\n`;
markdown += `**Timezone:** ${dashboardInfo.timezone}\n`;
markdown += `**Refresh Interval:** ${dashboardInfo.refresh}\n\n`;

if (dashboardInfo.description) {
  markdown += `## Dashboard Description\n${dashboardInfo.description}\n\n`;
}

markdown += `## Panel Analysis\n\n`;
markdown += `This dashboard contains ${items.length} panel(s) for analysis.\n\n`;

// Add each panel analysis
items.forEach((item, index) => {
  const panelData = item.json.panel;
  const analysis = item.json.response || 'Analysis not available';

  markdown += `### ${index + 1}. ${panelData.title}\n\n`;
  markdown += `**Panel ID:** ${panelData.id}\n`;
  markdown += `**Type:** ${panelData.type}\n`;

  if (panelData.description) {
    markdown += `**Description:** ${panelData.description}\n`;
  }

  markdown += `**Position:** Row ${panelData.gridPos?.y || 'Unknown'}, Column ${panelData.gridPos?.x || 'Unknown'}\n\n`;

  // Add SQL queries if available
  if (panelData.sql_queries && panelData.sql_queries.length > 0) {
    markdown += `**SQL Queries:**\n\n`;
    panelData.sql_queries.forEach(query => {
      markdown += `*RefID: ${query.refId} (${query.datasource})*\n`;
      markdown += `\`\`\`sql\n${query.sql}\n\`\`\`\n\n`;
    });
  }

  // Add LLM analysis
  markdown += `**Analysis:**\n${analysis}\n\n`;
  markdown += `---\n\n`;
});

// Add summary section
markdown += `## Summary\n\n`;
markdown += `This dashboard analysis covers ${items.length} panels across various visualization types. `;
markdown += `The panels provide insights into different aspects of the monitored system or business metrics.\n\n`;

// Add recommendations section
markdown += `## Recommendations\n\n`;
markdown += `1. **Regular Review**: Schedule periodic reviews of these panels to ensure they remain relevant\n`;
markdown += `2. **Performance Monitoring**: Monitor query performance for panels with complex SQL\n`;
markdown += `3. **Alert Configuration**: Consider setting up alerts for critical metrics displayed in these panels\n`;
markdown += `4. **Documentation Updates**: Keep this analysis document updated as panels are modified\n\n`;

// Add metadata
markdown += `## Analysis Metadata\n\n`;
markdown += `- **Generated by:** n8n Grafana Dashboard Analysis Workflow\n`;
markdown += `- **Timestamp:** ${new Date().toISOString()}\n`;
markdown += `- **Dashboard URL:** [View Dashboard]({{$node['Webhook - Dashboard Analysis'].json.query.grafana_url}}/d/${dashboardInfo.uid})\n`;

return { 
  markdown: markdown,
  dashboard_title: dashboardInfo.title,
  panel_count: items.length,
  analysis_date: analysisDate
};
